1	/**
2	 * CM6 adapter for outline mode's additive-only indentation decorations (see
3	 * docs/research/07-decoration-experiments-plan.md, Experiment 1). All depth
4	 * math lives in decorate.ts; this module only turns its facts into CM6
5	 * decorations, gated per-editor on outline mode via the public
6	 * `editorInfoField` — same gating pattern as keymap.ts's grammarExtension.
7	 *
8	 * Two mechanisms, because Obsidian renders atom kinds two different ways in
9	 * Live Preview:
10	 *
11	 * - Most lines (headings, paragraphs, list items, code fences, plain
12	 *   blockquotes) render as a real `.cm-line` that CM6 lets us decorate
13	 *   declaratively: one class plus one CSS custom property per fact (never
14	 *   an inline shorthand property), so styles.css owns the actual
15	 *   `padding-left`/`margin-left` rules and their units.
16	 * - Tables, callouts, raw HTML blocks, and horizontal rules are rendered as
17	 *   opaque replacement widgets (`.cm-embed-block`, or `.hr` for the rule) —
18	 *   confirmed live: a `Decoration.line` targeting that line's position has
19	 *   no effect at all (not even a class-merge partial win), because the
20	 *   widget's own `toDOM()` produces the line's DOM wholesale and neither
21	 *   CM6 nor Obsidian threads our decoration's class/attributes through it.
22	 *   These need a direct, imperative DOM patch instead — a `ViewPlugin`
23	 *   that, after each render, sets `margin-left` inline (with `!important`,
24	 *   which always wins for an inline style regardless of what any
25	 *   stylesheet rule does) on whichever such widgets are currently mounted.
26	 */
27	
28	import { RangeSetBuilder, StateField, type Extension, type EditorState } from '@codemirror/state';
29	import {
30	  Decoration,
31	  EditorView,
32	  ViewPlugin,
33	  type DecorationSet,
34	  type PluginValue,
35	} from '@codemirror/view';
36	import { editorInfoField } from 'obsidian';
37	import { parse } from '../parse';
38	import { decorate, type LineDecorationFact } from './decorate';
39	import type { ModeSource } from './keymap';
40	
41	function lineDecoration(fact: LineDecorationFact): Decoration {
42	  if (fact.isListItem) {
43	    return Decoration.line({
44	      class: 'to-decor-list',
45	      attributes: { style: `--to-supp-depth: ${fact.supplementalDepth}` },
46	    });
47	  }
48	  const cls = fact.isAtom ? 'to-decor-atom' : 'to-decor-block';
49	  return Decoration.line({ class: cls, attributes: { style: `--to-depth: ${fact.depth}` } });
50	}
51	
52	function computeDecorations(state: EditorState, modes: ModeSource): DecorationSet {
53	  const path = state.field(editorInfoField, false)?.file?.path;
54	  if (!path || !modes.isOutline(path)) return Decoration.none;
55	
56	  const facts = decorate(parse(state.doc.toString()));
57	  const totalLines = state.doc.lines;
58	  const builder = new RangeSetBuilder<Decoration>();
59	  for (const fact of facts) {
60	    if (fact.lineNumber >= totalLines) continue; // stale fact past a shrunk doc
61	    const from = state.doc.line(fact.lineNumber + 1).from; // CM6 lines are 1-indexed
62	    builder.add(from, from, lineDecoration(fact));
63	  }
64	  return builder.finish();
65	}
66	
67	// Obsidian's own selectors for widget-replaced atom kinds — matches tables,
68	// callouts, and raw HTML blocks (`.cm-embed-block`) plus horizontal rules
69	// (`.hr`, which oddly also carries `cm-line` but is widget-rendered all the
70	// same). Broad by design: elements it catches that don't correspond to an
71	// atom fact (e.g. an inline image embed inside a paragraph) just get their
72	// margin cleared, a no-op.
73	const WIDGET_ATOM_SELECTOR = '.cm-embed-block, .cm-line.hr';
74	
75	class AtomWidgetMargins implements PluginValue {
76	  constructor(
77	    private readonly view: EditorView,
78	    private readonly modes: ModeSource,
79	  ) {
80	    this.apply();
81	  }
82	
83	  docViewUpdate(): void {
84	    this.apply();
85	  }
86	
87	  destroy(): void {
88	    this.clearAll();
89	  }
90	
91	  private apply(): void {
92	    const path = this.view.state.field(editorInfoField, false)?.file?.path;
93	    if (!path || !this.modes.isOutline(path)) {
94	      this.clearAll();
95	      return;
96	    }
97	
98	    const factsByLine = new Map(
99	      decorate(parse(this.view.state.doc.toString())).map((f) => [f.lineNumber, f]),
100	    );
101	    const widgets = Array.from(
102	      this.view.contentDOM.querySelectorAll<HTMLElement>(WIDGET_ATOM_SELECTOR),
103	    );
104	    for (const el of widgets) {
105	      const fact = factsByLine.get(this.view.state.doc.lineAt(this.view.posAtDOM(el)).number - 1);
106	      if (fact?.isAtom) {
107	        // Some widgets (tables, for their row/column drag-handles) carry
108	        // their own native left padding that our margin doesn't know
109	        // about — padding never moves a box's own edge, so it just pushes
110	        // the widget's *visible content* (e.g. the <table> grid) further
111	        // right than a same-depth code block or callout, whose background
112	        // fills their own padding invisibly. Reading it live (not a
113	        // hardcoded constant) keeps this correct across themes; clamped at
114	        // 0 so a depth-0 atom never goes negative.
115	        const nativePaddingLeft = parseFloat(getComputedStyle(el).paddingLeft) || 0;
116	        el.style.setProperty(
117	          'margin-left',
118	          `max(0px, calc(${fact.depth} * var(--to-decor-unit, 1.5rem) - ${nativePaddingLeft}px))`,
119	          'important',
120	        );
121	      } else {
122	        el.style.removeProperty('margin-left');
123	      }
124	    }
125	  }
126	
127	  private clearAll(): void {
128	    const widgets = Array.from(
129	      this.view.contentDOM.querySelectorAll<HTMLElement>(WIDGET_ATOM_SELECTOR),
130	    );
131	    for (const el of widgets) el.style.removeProperty('margin-left');
132	  }
133	}
134	
135	export function decorationsExtension(modes: ModeSource): Extension {
136	  return [
137	    StateField.define<DecorationSet>({
138	      create: (state) => computeDecorations(state, modes),
139	      // Recomputes on every transaction, not just docChanged ones:
140	      // toggling outline mode has no doc change of its own, only a nudged
141	      // selection transaction (see main.ts) to make this field re-run.
142	      update: (_value, tr) => computeDecorations(tr.state, modes),
143	      provide: (field) => EditorView.decorations.from(field),
144	    }),
145	    ViewPlugin.define<AtomWidgetMargins>((view) => new AtomWidgetMargins(view, modes)),
146	  ];
147	}
