describe('computeGuides: guide-line spans (Experiment 2a)', () => {
  it('produces no guides for a flat, childless document', () => {
    const md = 'First.\n\nSecond.\n\nThird.\n';
    expect(computeGuides(parse(md))).toEqual([]);
  });

  it('produces no guide for a leaf node (no children)', () => {
    const md = '# Heading\n\nPara.\n';
    // Neither node has children, so no ancestor exists to hang a guide from.
    expect(computeGuides(parse(md))).toEqual([]);
  });

  it('one guide per ancestor, hanging from its own first line through its deepest descendant', () => {
    const md = [
      '# Section',
      '',
      '- top item',
      '  - nested item',
      '    - deeply nested item',
      '',
    ].join('\n');
    const guides = computeGuides(parse(md));

    // Lines: 0 "# Section", 2 "- top item", 3 "  - nested item",
    // 4 "    - deeply nested item".
    expect(guides).toContainEqual({ depth: 0, anchorLine: 0, fromLine: 2, toLine: 4 });
    expect(guides).toContainEqual({ depth: 1, anchorLine: 2, fromLine: 3, toLine: 4 });
    expect(guides).toContainEqual({ depth: 2, anchorLine: 3, fromLine: 4, toLine: 4 });
    expect(guides).toHaveLength(3); // "deeply nested item" is a leaf: no guide of its own
  });

  it('a guide spans from the first child to the LAST line of the deepest, last descendant', () => {
    const md = ['# Top', '', '- one', '- two', '  - two nested', '- three', ''].join('\n');
    const guides = computeGuides(parse(md));
    // Lines: 0 "# Top", 2 "- one", 3 "- two", 4 "  - two nested", 5 "- three".
    // "# Top"'s guide must reach past "- two"'s own nested child to "- three".
    const topGuide = guides.find((g) => g.anchorLine === 0)!;
    expect(topGuide.fromLine).toBe(2);
    expect(topGuide.toLine).toBe(5);
  });

  it('a guide spans through a multi-line (Shift+Enter continuation) descendant to its LAST line', () => {
    const md = ['- parent', '  - child first line', '    second line of child', ''].join('\n');
    const guides = computeGuides(parse(md));
    // Lines: 0 "- parent", 1 "  - child first line", 2 "    second line of child".
    expect(guides).toEqual([{ depth: 0, anchorLine: 0, fromLine: 1, toLine: 2 }]);
  });

  it('recomputes independently for separate subtrees (no cross-contamination)', () => {
    const md = ['# A', '', '- one', '', '## B', '', '- two', '  - two nested', ''].join('\n');
    const guides = computeGuides(parse(md));
    // "# A" (line 0) only reaches its own child "- one" (line 2).
    const aGuide = guides.find((g) => g.anchorLine === 0)!;
    expect(aGuide.fromLine).toBe(2);
    expect(aGuide.toLine).toBe(2);
    // "## B" (line 4) reaches through its own subtree only ("- two" at line
    // 6 through its nested child at line 7), not "# A"'s.
    const bGuide = guides.find((g) => g.anchorLine === 4)!;
    expect(bGuide.fromLine).toBe(6);
    expect(bGuide.toLine).toBe(7);
  });
});

