it('heading-then-list: one guide per ancestor, anchored at that ancestor’s own rendered position', async function () {
  const fixture = ALL_DECORATION_FIXTURES.find((f) => f.label === 'heading-then-list')!;
  await h.createNote(fixture.note, fixture.md);
  await ensureOutlineMode(fixture.note);
  await browser.pause(DEBOUNCE_SETTLE_MS);

  // Lines: 0 "# Section", 2 "- top item", 3 "  - nested item",
  // 4 "    - deeply nested item" (a leaf: no guide of its own). Each
  // guide's `fromLine` is strictly deeper (and so lower on screen) than
  // the shallower one's, so getGuideRects()'s top-ascending sort gives a
  // deterministic [Section, top item, nested item] correspondence here.
  const guides = await h.getGuideRects();
  expect(guides).toHaveLength(3);
  const [sectionGuide, topGuide, nestedGuide] = guides;

  // "# Section" has no native marker to hang from — its own line box
  // edge (padding-left) IS its rendered content start.
  const sectionRect = await h.getLineRect(0);
  expect(sectionGuide!.left).toBeCloseTo(sectionRect.left, 0);

  // List items hang their native bullet via a *negative* text-indent,
  // which can render the marker glyph outside the line's own padding
  // box — comparing against the line box's edge (as above) is the wrong
  // reference here; the bullet's own rect is the correct ground truth
  // (same selector the existing indentation e2e spec already uses).
  const topMarker = (await h.getLineChildRects(2, '.cm-formatting-list'))[0]!;
  expect(topGuide!.left).toBeCloseTo(topMarker.left, 0);

  const nestedMarker = (await h.getLineChildRects(3, '.cm-formatting-list'))[0]!;
  expect(nestedGuide!.left).toBeCloseTo(nestedMarker.left, 0);
});

