import { obsidianPage } from 'wdio-obsidian-service';
import * as h from '../helpers.js';
import { ALL_DECORATION_FIXTURES } from '../fixtures/decorations.js';

describe('debug mixed guides', function () {
  before(async function () {
    await obsidianPage.resetVault();
    await h.resetPluginState();
  });

  it('debug', async function () {
    const fixture = ALL_DECORATION_FIXTURES.find((f) => f.label === 'mixed')!;
    await h.createNote(fixture.note, fixture.md);
    if (!(await h.isOutlineMode(fixture.note))) {
      await h.toggleOutlineMode();
      await h.waitForNotice('Outline mode on');
      await h.dismissNotices();
    }
    await browser.pause(300);

    const buffer = await h.getBuffer();
    console.log('BUFFER lines:', JSON.stringify(buffer.split('\n')));

    const guides = await h.getGuideRects();
    console.log('guides count', guides.length);
    console.log('guides', JSON.stringify(guides, null, 2));

    const line0 = await h.getLineRect(0); // "# Top"
    console.log('line0 (# Top) rect', JSON.stringify(line0));

    expect(true).toBe(true);
  });
});

